#include <bits/stdc++.h>
using namespace std;

class NStacks {
private:
    vector<int> arr;           // main array for N stacks
    vector<int> top;           // top indices for each stack
    vector<int> next;          // next free position for each entry
    int free;                  // next free position in array

public:
    NStacks(int N, int S) {
        arr.resize(S);
        top.resize(N, -1);     // initialize tops as -1
        next.resize(S);

        // Initialize all spaces as free
        for(int i = 0; i < S-1; i++)
            next[i] = i + 1;
        next[S-1] = -1;        // last entry points to -1

        free = 0;              // initialize free position
    }

    bool push(int X, int M) {
        // Check if we have free space
        if(free == -1) return false;

        // Get free index
        int i = free;

        // Update free by pointing to next free index
        free = next[i];

        // Insert element into array
        arr[i] = X;

        // Update next of current index to point to previous top
        next[i] = top[M-1];

        // Update top of stack
        top[M-1] = i;

        return true;
    }

    int pop(int M) {
        // Check if stack is empty
        if(top[M-1] == -1) return -1;

        // Get top index
        int i = top[M-1];

        // Update top to point to next element
        top[M-1] = next[i];

        // Add the popped index to free list
        next[i] = free;
        free = i;

        return arr[i];
    }
};

int main() {
    int N, S, Q;
    cin >> N >> S >> Q;

    NStacks stacks(N, S);

    while(Q--) {
        int type;
        cin >> type;

        if(type == 1) {
            int X, M;
            cin >> X >> M;
            cout << (stacks.push(X, M) ? "True" : "False") << endl;
        } else {
            int M;
            cin >> M;
            cout << stacks.pop(M) << endl;
        }
    }

    return 0;
}
